import kotlin.test.*
import test.TestPlatform
import test.testExceptOn

class AllDistinctFloatArrayTest {

    @Test
    fun allDistinct() {
        assertTrue(floatArrayOf().allDistinct())
        assertTrue(floatArrayOf(1.0f).allDistinct())
        assertTrue(floatArrayOf(1.0f, 2.0f).allDistinct())
        assertFalse(floatArrayOf(1.0f, 1.0f).allDistinct())
        assertFalse(floatArrayOf(2.0f, 2.0f).allDistinct())
        assertFalse(floatArrayOf(1.0f, 2.0f, 1.0f).allDistinct())
        assertFalse(floatArrayOf(2.0f, 1.0f, 2.0f).allDistinct())
    }

    @Test
    fun allDistinctBy() {
        assertTrue(floatArrayOf().allDistinctBy { it * it })
        assertTrue(floatArrayOf(1.0f).allDistinctBy { it * it })
        assertTrue(floatArrayOf(1.0f).allDistinctBy { error("should not be called") })
        assertTrue(floatArrayOf(1.0f, 2.0f).allDistinctBy { it * it })
        assertFalse(floatArrayOf(1.0f, -1.0f, 1.0f).allDistinctBy { it * it })
        assertFalse(floatArrayOf(1.0f, 2.0f).allDistinctBy { 0 })
        assertFalse(floatArrayOf(1.0f, 2.0f).allDistinctBy { null })
    }

    @Test
    fun allDistinctNaNFloat() {
        assertTrue(floatArrayOf(Float.NaN).allDistinct())
        assertTrue(floatArrayOf(Float.NaN, 1.0f).allDistinct())
        assertFalse(floatArrayOf(Float.NaN, Float.NaN).allDistinct())
        assertFalse(floatArrayOf(Float.NaN, Float.NaN, Float.NaN).allDistinct())
        assertFalse(floatArrayOf(Float.NaN, 1.0f, Float.NaN).allDistinct())
    }

    @Test
    fun allDistinctNegativeZeroFloat() {
        assertTrue(floatArrayOf(0.0f, -0.0f).allDistinct())
        assertFalse(floatArrayOf(0.0f, 0.0f).allDistinct())
        assertFalse(floatArrayOf(-0.0f, -0.0f).allDistinct())
    }

    @Test
    fun allDistinctByNaNFloat() {
        assertTrue(floatArrayOf(Float.NaN, 1.0f).allDistinctBy { it })
        assertFalse(floatArrayOf(Float.NaN, Float.NaN).allDistinctBy { it })
        assertFalse(floatArrayOf(Float.NaN, 1.0f, Float.NaN).allDistinctBy { it })
    }

    @Test
    fun allDistinctByNegativeZeroFloat() {
        assertTrue(floatArrayOf(0.0f, -0.0f).allDistinctBy { it })
        assertFalse(floatArrayOf(0.0f, 0.0f).allDistinctBy { it })
    }

    @Test
    fun allDistinctDifferentNaNBitsFloat() {
        // JS hashCode doesn't canonicalize NaN, so a HashSet keeps distinct NaN bit patterns apart.
        testExceptOn(TestPlatform.Js) {
            assertFalse(floatArrayOf(Float.NaN, Float.fromBits(0xFFFC0000.toInt())).allDistinct())
            assertFalse(floatArrayOf(Float.NaN, Float.fromBits(0xFFFC0000.toInt()), Float.fromBits(0x7FC00001)).allDistinct())
            assertFalse(floatArrayOf(Float.fromBits(0x7FC00001), Float.fromBits(0xFFFC0000.toInt()), Float.NaN).allDistinct())
        }
        assertTrue(floatArrayOf(Float.NaN, 1.0f).allDistinct())
        assertTrue(floatArrayOf(0.0f, 1.0f).allDistinct())
    }

    @Test
    fun allDistinctByDifferentNaNBitsFloat() {
        // JS hashCode doesn't canonicalize NaN, so a HashSet keeps distinct NaN bit patterns apart.
        testExceptOn(TestPlatform.Js) {
            assertFalse(floatArrayOf(Float.NaN, Float.fromBits(0xFFFC0000.toInt())).allDistinctBy { it })
            assertFalse(floatArrayOf(Float.NaN, Float.fromBits(0xFFFC0000.toInt()), Float.fromBits(0x7FC00001)).allDistinctBy { it })
        }
        assertTrue(floatArrayOf(Float.NaN, 1.0f).allDistinctBy { it })
    }
